export function DevicesSection() {
  return (
    <section className="bg-[#141414] py-16 px-4">
      <div className="max-w-350 3xl:max-w-400 mx-auto">
        <div className="mb-12">
          <h2 className="text-white text-3xl 3xl:text-5xl font-bold mb-4">
            We Provide you streaming experience across various devices.
          </h2>
          <p className="text-gray-400 text-sm 3xl:text-lg max-w-4xl 3xl:max-w-full">
            With StreamVibe, you can enjoy your favorite movies and TV shows
            anytime, anywhere. Our platform is designed to be compatible with a
            wide range of devices, ensuring that you never miss a moment of
            entertainment.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {devicesData.map((device, index) => (
            <DeviceCard
              key={index}
              title={device.title}
              description={device.description}
              icon={device.icon}
            />
          ))}
        </div>
      </div>
    </section>
  );
}
